frappe.ui.form.on('Branch', {

    validate: function(frm) {
        // Guard Check: Pass straight through if transaction has already been approved
        if (frm.doc.__reassignment_approved) {
            delete frm.doc.__reassignment_approved;
            return;
        }

        // Freeze the standard synchronous save action loop
        frappe.validated = false;

        // Pass 1: Run the backend dry-run validation check scoped to the active company context
        frappe.call({
            method: 'smart_invoice_app.scripts.branch.check_default_branch_conflicts',
            args: {
                current_branch: frm.doc.name || "",
                child_table_rows: frm.doc.custom_branch_users || [],
                company: frm.doc.custom_company || ""
            },
            callback: function(r) {
                if (r.message && r.message.has_conflicts) {
                    let conflicts = r.message.conflicts;

                    // Build an informative summary description layout list
                    let conflicts_html = conflicts.map(c => 
                        `<li><b>${c.user_id}</b>'s current default branch is <b>${c.branch}</b></li>`
                    ).join('');

                    // Evaluate layout counts to dynamically assign clean string variations
                    let is_plural = conflicts.length > 1;
                    let company_name = frm.doc.custom_company;

                    let modal_title = is_plural 
                        ? __('Update Default Branches?') 
                        : __('Update Default Branch?');

                    let modal_body = is_plural
                        ? __(`These users are already set as default in another <b>${company_name}</b> branch:<br><ol>${conflicts_html}</ol><br>Do you want to update?`)
                        : __(`This user is already set as default in another <b>${company_name}</b> branch:<br><ol>${conflicts_html}</ol><br>Do you want to update?`);

                    // Pass 2: Display the native Frappe Confirmation workflow modal with dynamic copy formatting
                    frappe.confirm(
                        `<b>${modal_title}</b><br><br>${modal_body}`,
                        () => {
                            // OPTION YES: Force atomic backend data cleanup resolution script
                            let user_ids_to_resolve = conflicts.map(c => c.user_id);

                            frappe.call({
                                method: 'smart_invoice_app.scripts.branch.resolve_and_save_branch_conflicts',
                                args: {
                                    current_branch: frm.doc.name || "",
                                    user_ids: user_ids_to_resolve,
                                    company: frm.doc.custom_company || ""
                                },
                                callback: function(res) {
                                    if (res.message && res.message.success) {
                                        // Set approval flag and re-trigger native save lifecycle
                                        frm.doc.__reassignment_approved = true;
                                        frm.save();
                                    }
                                }
                            });
                        },
                        () => {
                            // OPTION NO: Revert the conflicting selections inside this local form state context
                            // let conflicting_user_ids = conflicts.map(c => c.user_id);
                            // 
                            // frm.doc.custom_branch_users.forEach(row => {
                            //      if (conflicting_user_ids.includes(row.user_id)) {
                            //          frappe.model.set_value(row.doctype, row.name, 'is_default', 0);
                            //      }
                            // });
                            // 
                            // frappe.show_alert({
                            //      message: __('Unsellect.'),
                            //      indicator: 'orange'
                            // });
                            // 
                            // frm.reload_doc();
                        }
                    );
                } else {
                    // No conflicts found: Safe to proceed with normal database commit save operations
                    frm.doc.__reassignment_approved = true;
                    frm.save();
                }
            }
        });
    },
	refresh(frm) {

        // Custom filter function to exclude existing users
        frm.set_query("user_id", "custom_branch_users", function(doc) {
            existing_users = frm.doc.custom_branch_users.map(row => row.user_id);
            return{
                filters: {
                    "name": ["not in", existing_users]
                }
            };
        });

        frm.set_query("custom_branch_status", function() {
            return {
                filters: {
                    "cd_cls": ["in", ["09"]]
                }
            };
        });

	},
	setup(frm) {
        // Prevent layout shifting and wobbling when global progress overlays load
        document.documentElement.style.scrollbarGutter = "stable";

        // Listen for final logic to trigger alerts and reload the specific form
        frappe.realtime.on("sync_progress", function(data) {
            // 1. Scoping Guard: Ensure this event belongs to the active document on screen
            if (data.docname && data.docname !== frm.doc.name) {
                return; 
            }

            let indicator = data.indicator;
            let message = data.message || __("Sync failure without an explicit error message.");

            if (["green", "blue"].includes(indicator)) {
                frappe.show_alert({ message: message, indicator: indicator}, 2);
            } else {
                frappe.warn(
                    __("Smart Invoice encountered the following error:"),
                    `${message}<br>`, // Message body
                    () => {
                        // Primary Action: Redirect to the sync log document if name exists
                        frappe.set_route("Form", "Sync Request", data.name);
                    },
                    __("Open"),
                );
            }
        });

        // Listen for final logic execution to reload the document details
        frappe.realtime.on("reload_form", function(data) {
            // Optional verification to confirm context matches session modifier/document
            frm.reload_doc();
        });
    },
    unload: function(frm) {
        // Clean up listener when leaving the form to prevent memory leaks
        frappe.realtime.off('sync_progress');
        frappe.realtime.off('progress');
    },
	after_save(frm){
	    frappe.call({
	        method: "smart_invoice_app.app.update_smart_invoice_users",
	        args: {
	            branch: frm.doc.branch
	        },
    		freeze: true,
    		freeze_message: __("Updating the branch and its users ..."),
	        callback: (r)=>{
