function setup_field_filters(frm) {
    frm.set_query("custom_pkg_unit", function() {
        return { filters: { "custom_code_class_name": ["in", ["17"]] } };
    });

    frm.set_query("item_tax_template", "taxes", function() {
        if ([""].includes(frm.doc.custom_industry_tax_type)) {
            return { filters: {} };
        }
        else if (frm.doc.custom_industry_tax_type == "TOT") {
            return { filters: { "custom_code": ["in", ["TOT"]] } };
        }
        else if (frm.doc.custom_industry_tax_type == "VAT") {
            return { filters: { "custom_code": ["in", ["A", "B", "RVAT"]] } };
        }
        else if (frm.doc.custom_industry_tax_type == "Zero Rated (VAT)") {
            return { filters: { "custom_code": ["in", ["C1", "C2", "C3", "E", "D"]] } };
        }
        else if (frm.doc.custom_industry_tax_type == "Excise Duty") {
            return { filters: { "custom_code": ["in", ["ECM", "EXEEG"]] } };
        }
        else if (frm.doc.custom_industry_tax_type == "Tourism Levy") {
            return { filters: { "custom_code": ["like", "TL%"] } };
        }
        else if (frm.doc.custom_industry_tax_type == "Insurance Premium Levy") {
            return { filters: { "custom_code": ["like", "IPL%"] } };
        }
    });

    frm.set_query("stock_uom", function() {
        return { filters: { "custom_code_class_name": ["in", ["10"]] } };
    });
    frm.set_query("custom_excise_tax_category", function() {
        return { filters: { "cd_cls": ["in", ["60"]] } };
    });
    frm.set_query("custom_insurance_premium_levy_category", function() {
        return { filters: { "cd_cls": ["in", ["61"]] } };
    });
    frm.set_query("custom_tourism_levy_type", function() {
        return { filters: { "cd_cls": ["in", ["62"]] } };
    });

    // item_class field in child table should only allow level 3 classes
    frm.set_query("custom_item_cls", function() {
        return { filters: {'item_cls_lvl': "3"} };
    });
}

function generate_item_code(frm){
    if (!frm.doc.custom_generated_item_code){
        frappe.call({
            method: "smart_invoice_app.app.generate_item_code",
            args: {
                item: frm.doc,
                initialize: false
            },
            freeze: true,
            freeze_message: __("Generating Smart Invoice Item Code ..."),
            callback: (r)=>{
                if(!r.error && r.message && r.message != frm.doc.custom_generated_item_code){
                    frm.set_value("custom_generated_item_code", r.message);
                    frm.refresh_field("custom_generated_item_code");
                }
            }
        });
    }
}

